'use client';

import { useState, useRef, useEffect } from 'react';
import styles from './intake.module.css';
import { Send, User, Bot, Sparkles } from 'lucide-react';

interface Message {
    role: 'user' | 'assistant';
    content: string;
}

export default function IntakeChat() {
    const [messages, setMessages] = useState<Message[]>([
        {
            role: 'assistant',
            content: "Hi. I'm here to help you find the kind of support that feels right for you. You can tell me as much or as little as you want. What has been weighing on you lately?"
        }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLoading) return;

        const userMessage: Message = { role: 'user', content: input };
        setMessages(prev => [...prev, userMessage]);
        setInput('');
        setIsLoading(true);

        try {
            const response = await fetch('/api/ai/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ messages: [...messages, userMessage] }),
            });

            if (!response.body) throw new Error('No response body');

            const reader = response.body.getReader();
            const decoder = new TextDecoder();
            let assistantContent = '';

            setMessages(prev => [...prev, { role: 'assistant', content: '' }]);

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;

                const token = decoder.decode(value);
                assistantContent += token;

                setMessages(prev => {
                    const lastIndex = prev.length - 1;
                    const updated = [...prev];
                    updated[lastIndex] = { role: 'assistant', content: assistantContent };
                    return updated;
                });
            }
        } catch (error) {
            console.error('Chat error:', error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={styles.container}>
            <div className={styles.chatWindow}>
                <div className={styles.messages} ref={scrollRef}>
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`${styles.messageWrapper} ${styles[msg.role]}`}>
                            <div className={styles.avatar}>
                                {msg.role === 'assistant' ? <Bot size={20} /> : <User size={20} />}
                            </div>
                            <div className={styles.bubble}>
                                {msg.content}
                            </div>
                        </div>
                    ))}
                    {isLoading && messages[messages.length - 1].role === 'user' && (
                        <div className={`${styles.messageWrapper} ${styles.assistant}`}>
                            <div className={styles.avatar}>
                                <Sparkles size={20} className={styles.pulse} />
                            </div>
                            <div className={styles.bubble}>
                                Thinking...
                            </div>
                        </div>
                    )}
                </div>

                <form onSubmit={handleSubmit} className={styles.inputArea}>
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder="Type your thoughts here..."
                        className={styles.input}
                        disabled={isLoading}
                    />
                    <button type="submit" className={styles.sendBtn} disabled={isLoading || !input.trim()}>
                        <Send size={20} />
                    </button>
                </form>
            </div>

            <div className={styles.sidebar}>
                <h3>Your Safe Space</h3>
                <p>Take your time. You do not need to explain everything at once.</p>
                <div className={styles.privacyNote}>
                    Your conversations stay private. The AI helps with matching. You choose what happens next.
                </div>
            </div>
        </div>
    );
}
